import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, Info, Plus, Search, MessageCircle, HelpCircle, LayoutDashboard, Users
} from 'lucide-react';

const Login = () => {
  // --- 1. STATE MANAGEMENT ---
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [showSupport, setShowSupport] = useState(false); 
  const [userRequests, setUserRequests] = useState([]); 
  const [selectedFileName, setSelectedFileName] = useState(""); 

  // --- 2. PERSISTENCE & INITIAL LOAD ---
  useEffect(() => {
    const token = localStorage.getItem('token');
    const role = localStorage.getItem('userRole');
    const userId = localStorage.getItem('userId');
    
    if (token) {
      setIsLoggedIn(true);
      if (role === 'admin') setView('admin-dashboard');
      else {
        setView('dashboard');
        if (userId) fetchRequests(userId);
      }
    }
  }, []);

  const fetchRequests = async (userId) => {
    try {
      const res = await axios.get(`http://localhost:5000/api/requests/user/${userId}`);
      setUserRequests(res.data);
    } catch (err) { console.log("Tracking error:", err); }
  };

  // --- 3. AUTHENTICATION (LOGIN/REGISTER) ---
  const handleAuth = async (e) => {
    e.preventDefault();
    const mode = view === 'register' ? 'register' : 'login';
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
      if (mode === 'login') {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userId', res.data.user._id);
        localStorage.setItem('userName', res.data.user.name);
        localStorage.setItem('userRole', res.data.user.role);
        setIsLoggedIn(true);
        if (res.data.user.role === 'admin') setView('admin-dashboard');
        else setView('dashboard');
      } else {
        alert("Account Created! Please Sign In.");
        setView('login');
      }
    } catch (err) { alert("Authentication Failed"); }
  };

  // --- 4. NATIVE FILE EXPLORER LOGIC ---
  const handleNativeUpload = async () => {
    try {
      const [fileHandle] = await window.showOpenFilePicker({
        types: [{ description: 'Docs', accept: { 'image/*': ['.png', '.jpg'], 'application/pdf': ['.pdf'] } }],
        multiple: false
      });
      const file = await fileHandle.getFile();
      setSelectedFileName(file.name);
    } catch (err) { console.log("Picker cancelled"); }
  };

  // --- 5. APPLICATION SUBMISSION ---
  const handleCredentialSubmit = async (e) => {
    e.preventDefault();
    const requestBody = {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
      documentUrl: selectedFileName || "application_document.pdf"
    };
    try {
      const res = await axios.post('http://localhost:5000/api/requests/submit', requestBody);
      setUserRequests([res.data.request, ...userRequests]);
      setShowModal(false);
      setSelectedFileName("");
      alert("✅ Application Submitted!");
      setActiveTab('tracking'); 
    } catch (err) { alert("Submission Failed."); }
  };

  // --- UI COMPONENTS ---
  const SupportModal = () => (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[200]">
      <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl p-10 animate-in zoom-in duration-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-black text-slate-900 flex items-center gap-2"><HelpCircle className="text-blue-600"/> Help Center</h2>
          <button onClick={() => setShowSupport(false)}><X className="text-slate-300 hover:text-slate-600"/></button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); alert("Ticket Sent!"); setShowSupport(false); }} className="space-y-4">
          <textarea placeholder="Describe issue..." className="w-full p-4 bg-slate-50 rounded-2xl h-32 outline-none border-none" required></textarea>
          <button className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black">Send Ticket</button>
        </form>
      </div>
    </div>
  );

  // ==========================================
  // VIEW: LANDING PAGE
  // ==========================================
  if (view === 'landing') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        <div className="mb-12">
           <div className="inline-block bg-blue-600 p-4 rounded-3xl mb-4 text-white shadow-xl shadow-blue-200"><ShieldCheck size={48} /></div>
           <h1 className="text-5xl font-black text-slate-900 tracking-tight italic uppercase">QUAD SOLUTIONS</h1>
           <p className="text-slate-500 font-medium italic">Credentialing Engine</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl w-full">
          <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition group text-left">
             <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center mb-6 text-blue-600 group-hover:scale-110 transition"><UserPlus size={32} /></div>
             <h2 className="text-2xl font-black text-slate-800 mb-2">New Providers</h2>
             <div className="flex items-center text-blue-600 font-bold group-hover:gap-2 transition-all">Get Started <ArrowRight size={20} className="ml-2" /></div>
          </div>
          <div onClick={() => setView('login')} className="bg-slate-900 p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition group text-white text-left">
             <div className="w-16 h-16 bg-white/10 rounded-2xl flex items-center justify-center mb-6 text-blue-400 group-hover:scale-110 transition"><LogIn size={32} /></div>
             <h2 className="text-2xl font-black mb-2">Existing Clients</h2>
             <div className="flex items-center text-blue-400 font-bold group-hover:gap-2 transition-all">Sign In <ArrowRight size={20} className="ml-2" /></div>
          </div>
        </div>
      </div>
    );
  }

  // ==========================================
  // VIEW: LOGIN / REGISTER
  // ==========================================
  if (view === 'login' || view === 'register') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
          <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 hover:text-slate-600 font-bold">Back</button>
          <h2 className="text-4xl font-black mb-8 text-slate-900 italic">{view === 'login' ? 'Login' : 'Register'}</h2>
          <form onSubmit={handleAuth} className="space-y-4">
            {view === 'register' && <input type="text" placeholder="Full Name" className="w-full p-4 bg-slate-50 rounded-2xl outline-none border-none font-bold" onChange={(e) => setFormData({...formData, name: e.target.value})} required />}
            <input type="email" placeholder="Email" className="w-full p-4 bg-slate-50 rounded-2xl outline-none border-none font-bold" onChange={(e) => setFormData({...formData, email: e.target.value})} required />
            <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl outline-none border-none font-bold" onChange={(e) => setFormData({...formData, password: e.target.value})} required />
            <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg hover:bg-blue-700 transition">Continue</button>
            <p onClick={() => setView(view === 'login' ? 'register' : 'login')} className="text-center text-slate-400 font-bold cursor-pointer mt-4 italic underline underline-offset-4">Switch to {view === 'login' ? 'Register' : 'Login'}</p>
          </form>
        </div>
      </div>
    );
  }

  // ==========================================
  // VIEW: ADMIN DASHBOARD
  // ==========================================
  if (view === 'admin-dashboard') {
    return (
      <div className="min-h-screen bg-slate-900 text-white flex flex-col">
        <nav className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-950">
          <div className="flex items-center gap-3"><LayoutDashboard className="text-blue-400" /><h1 className="text-xl font-black tracking-widest text-blue-400 uppercase italic">Admin Portal</h1></div>
          <button onClick={() => {localStorage.clear(); window.location.reload();}} className="bg-red-600/20 text-red-500 px-6 py-2 rounded-xl font-black hover:bg-red-600 hover:text-white transition">Logout</button>
        </nav>
        <main className="p-10 max-w-7xl mx-auto w-full">
           <h2 className="text-3xl font-black mb-8 flex items-center gap-2"><Users /> Management Overview</h2>
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
              <div className="bg-slate-800/50 p-8 rounded-[2rem] border border-slate-700"><p className="text-slate-500 font-bold text-xs uppercase mb-1">Total Providers</p><h4 className="text-4xl font-black">24</h4></div>
              <div className="bg-slate-800/50 p-8 rounded-[2rem] border border-slate-700 border-l-4 border-l-yellow-500"><p className="text-slate-500 font-bold text-xs uppercase mb-1">Pending Documents</p><h4 className="text-4xl font-black text-yellow-500">{userRequests.length}</h4></div>
              <div className="bg-slate-800/50 p-8 rounded-[2rem] border border-slate-700 border-l-4 border-l-green-500"><p className="text-slate-500 font-bold text-xs uppercase mb-1">Approved Today</p><h4 className="text-4xl font-black text-green-500">12</h4></div>
           </div>
           <div className="bg-slate-800/40 rounded-[3rem] border border-slate-800 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-950/50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b border-slate-800">
                  <tr><th className="p-8">Provider</th><th className="p-8">Type</th><th className="p-8">Status</th><th className="p-8">Document</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {userRequests.map((req) => (
                    <tr key={req._id} className="hover:bg-slate-800/60 transition group border-t border-slate-800/50">
                      <td className="p-8 font-bold">{req.userName}</td>
                      <td className="p-8 text-slate-400">{req.type}</td>
                      <td className="p-8"><span className="text-yellow-500 bg-yellow-500/10 px-4 py-1 rounded-full text-[10px] font-black uppercase">Pending Review</span></td>
                      <td className="p-8 text-center text-slate-500"><FileText size={18} className="mx-auto cursor-pointer hover:text-blue-400"/></td>
                    </tr>
                  ))}
                </tbody>
              </table>
           </div>
        </main>
      </div>
    );
  }

  // ==========================================
  // VIEW: NORMAL USER DASHBOARD
  // ==========================================
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <nav className="bg-white shadow-sm p-4 sticky top-0 z-50 border-b">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
          <div className="flex gap-4 items-center">
             <button onClick={() => setActiveTab('services')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-slate-600 transition'}`}>Services</button>
             <button onClick={() => setActiveTab('tracking')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-slate-600 transition'}`}>My Status</button>
             <button onClick={() => setShowSupport(true)} title="Contact Support" className="p-2 text-slate-400 hover:text-blue-600 transition"><HelpCircle size={24}/></button>
             <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold px-2 hover:scale-110 transition"><LogOut size={20}/></button>
          </div>
        </div>
      </nav>

      <main className="p-10 max-w-5xl mx-auto w-full">
        {activeTab === 'services' ? (
          <section className="animate-in fade-in duration-500">
             <h2 className="text-3xl font-black text-slate-900 mb-8">Service Catalog</h2>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                  { t: 'Medical License Renewal', i: <FileText/> },
                  { t: 'Insurance Enrollment', i: <Activity/> },
                  { t: 'DEA Certification', i: <ShieldCheck/> }
                ].map((item, idx) => (
                  <div key={idx} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300">
                    <div className="w-12 h-12 bg-blue-50 rounded-xl flex items-center justify-center mb-4 text-blue-600">{item.i}</div>
                    <h3 className="text-xl font-bold mb-2">{item.t}</h3>
                    <p className="text-slate-400 text-sm mb-4 italic">Verification for {item.t.toLowerCase()}.</p>
                    <button onClick={() => setShowModal(true)} className="w-full bg-slate-900 text-white py-3 rounded-xl font-bold mt-4 hover:bg-blue-600 transition uppercase text-xs">Apply Now</button>
                  </div>
                ))}
             </div>
          </section>
        ) : (
          <section className="animate-in fade-in duration-500">
             <div className="flex justify-between items-end mb-8">
                <div>
                   <h2 className="text-3xl font-black text-slate-900 italic uppercase tracking-tighter">Tracking History</h2>
                   <p className="text-slate-400 text-xs font-bold uppercase mt-1">Monitor your verification progress</p>
                </div>
                <div className="bg-blue-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-lg shadow-blue-200">
                   {userRequests.length} Active Requests
                </div>
             </div>

             <div className="space-y-4">
                {userRequests.length === 0 ? (
                   <div className="bg-white p-20 rounded-[3rem] text-center border-2 border-dashed border-slate-100">
                      <Clock className="mx-auto text-slate-200 mb-4" size={48}/>
                      <p className="text-slate-300 font-bold uppercase text-sm tracking-widest">No history found</p>
                   </div>
                ) : (
                   userRequests.map((req, idx) => (
                      <div key={req._id} className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 p-8 flex flex-col md:flex-row justify-between items-center hover:shadow-xl transition-all duration-300 group">
                         <div className="flex items-center gap-6 text-left">
                            <div className="w-16 h-16 bg-slate-900 rounded-[1.5rem] flex flex-col items-center justify-center text-white shadow-xl group-hover:bg-blue-600 transition-colors">
                               <span className="text-[10px] font-black opacity-50 uppercase">REQ</span>
                               <span className="text-xl font-black italic">0{idx + 1}</span>
                            </div>
                            <div>
                               <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">{req.type}</h3>
                               <div className="flex items-center gap-4 mt-1">
                                  <p className="text-slate-400 font-bold text-[10px] uppercase flex items-center gap-1"><ShieldCheck size={12}/> ID: {req.licenseNumber}</p>
                                  <p className="text-slate-400 font-bold text-[10px] uppercase flex items-center gap-1"><Clock size={12}/> {new Date(req.submittedDate).toLocaleDateString()}</p>
                               </div>
                            </div>
                         </div>
                         <div className="flex items-center gap-4 mt-4 md:mt-0">
                            <div className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 ${req.status === 'Approved' ? 'bg-green-100 text-green-600' : 'bg-blue-100 text-blue-600'}`}>
                               <div className={`w-2 h-2 rounded-full animate-pulse ${req.status === 'Approved' ? 'bg-green-500' : 'bg-blue-500'}`}></div>
                               {req.status}
                            </div>
                            <div title={req.documentUrl} className="p-3 bg-slate-50 rounded-xl text-slate-400 hover:text-blue-600 transition cursor-pointer border border-slate-100">
                               <FileText size={20}/>
                            </div>
                         </div>
                      </div>
                   ))
                )}
             </div>
          </section>
        )}
      </main>

      {/* --- SUBMISSION MODAL --- */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl p-10 animate-in zoom-in duration-200">
            <h2 className="text-2xl font-black mb-6 text-blue-600 uppercase italic underline underline-offset-8">New Submission</h2>
            <form onSubmit={handleCredentialSubmit} className="space-y-4">
              <select className="w-full p-4 bg-slate-50 rounded-2xl border-none font-bold text-slate-700 outline-none"><option>Medical License</option><option>Insurance Enrollment</option><option>DEA Certification</option></select>
              <input type="text" placeholder="License / NPI ID" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold border-none" required />
              
              <div onClick={handleNativeUpload} className="mt-1 p-8 bg-blue-50 rounded-2xl border-2 border-dashed border-blue-200 text-center cursor-pointer hover:bg-blue-100 transition group">
                <Upload className="mx-auto text-blue-400 mb-2 group-hover:scale-110 transition" size={28}/>
                <p className="text-[10px] font-black text-blue-600 uppercase tracking-tighter">
                   {selectedFileName ? `SELECTED: ${selectedFileName}` : "Click to Upload Document"}
                </p>
                <p className="text-[10px] text-slate-400 mt-1 italic">Opens native explorer directly</p>
              </div>

              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black mt-4 shadow-xl shadow-blue-100 hover:bg-blue-700 transition">Confirm Submission</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full text-slate-400 font-bold text-sm">Cancel</button>
            </form>
          </div>
        </div>
      )}
      {showSupport && <SupportModal />}
    </div>
  );
};

export default Login;
